     2→import React, { useState } from 'react'
     3→import { AnimatePresence, motion, useMotionValue, useSpring, useTransform } from 'framer-motion'
     4→
     5→export const AnimatedTooltip = ({items}: {
     6→  items: {
     7→    id: number;
     8→    name: string;
     9→    color: string;
    10→    icon: string;
    11→  }[];
    12→}) => {
    13→  const [hoveredIndex, setHoveredIndex] = useState<number | null>(null);
    14→  const springConfig = { stiffness: 100, damping: 5 };
    15→  const x = useMotionValue(0); // going to set this value on mouse move
    16→  // rotate the tooltip
    17→  const rotate = useSpring(
    18→    useTransform(x, [-100, 100], [-45, 45]),
    19→    springConfig
    20→  );
    21→  // translate the tooltip
    22→  const translateX = useSpring(
    23→    useTransform(x, [-100, 100], [-50, 50]),
    24→    springConfig
    25→  );
    26→  const handleMouseMove = (event: any) => {
    27→    const halfWidth = event.target.offsetWidth / 2;
    28→    x.set(event.nativeEvent.offsetX - halfWidth); // set the x value, which is then used in transform and rotate
    29→  };
    30→
    31→  return (
    32→    <>
    33→      {items.map((item, idx) => (
    34→        <div
    35→          className="relative group"
    36→          key={item.name}
    37→          onMouseEnter={() => setHoveredIndex(item.id)}
    38→          onMouseLeave={() => setHoveredIndex(null)}
    39→        >
    40→          <AnimatePresence mode="wait">
    41→            {hoveredIndex === item.id && (
    42→              <motion.div
    43→                initial={{ opacity: 0, y: 20, scale: 0.6 }}
    44→                animate={{
    45→                  opacity: 1,
    46→                  y: 0,
    47→                  scale: 1,
    48→                  transition: {
    49→                    type: "spring",
    50→                    stiffness: 260,
    51→                    damping: 10,
    52→                  },
    53→                }}
    54→                exit={{ opacity: 0, y: 20, scale: 0.6 }}
    55→                style={{
    56→                  translateX: translateX,
    57→                  rotate: rotate,
    58→                  whiteSpace: "nowrap",
    59→                }}
    60→                className="absolute -top-16 -left-1/2 translate-x-1/2 flex text-xs  flex-col items-center justify-center rounded-md bg-black z-50 shadow-xl px-4 py-2"
    61→              >
    62→                <div className="absolute inset-x-10 z-30 w-[20%] -bottom-px bg-gradient-to-r from-transparent via-emerald-500 to-transparent h-px " />
    63→                <div className="absolute left-10 w-[40%] z-30 -bottom-px bg-gradient-to-r from-transparent via-sky-500 to-transparent h-px " />
    64→                <div className="font-bold text-white relative z-30 text-base">
    65→                  {item.name}
    66→                </div>
    67→              </motion.div>
    68→            )}
    69→          </AnimatePresence>
    70→          <img
    71→            onMouseMove={handleMouseMove}
    72→            height={100}
    73→            width={100}
    74→            src={item.icon}
    75→            alt={item.name}
    76→            className="object-cover !m-0 !p-0 object-top rounded-full md:h-11 md:w-11 group-hover:scale-105 group-hover:z-30 transition duration-500"
    77→          />
    78→        </div>
    79→      ))}
    80→    </>
    81→  );
    82→};

